import { Card, CardContent, Divider, IconButton, Link, useMediaQuery } from "@mui/material";
import Box from "@mui/material/Box";
import Container from "@mui/material/Container";
import Grid from "@mui/material/Grid";
import Typography from "@mui/material/Typography";
import { useTheme } from '@mui/material/styles';
import { navigate } from "gatsby";
import React, { useEffect, useState } from "react";
import ButtonInput from "../components/ButtonInput/ButtonInput";
import CustomButton from "../components/CustomButton/CustomButton";
import Layout from "../components/Layout";
import QuantityInput from "../components/QuantityInput/QuantityInput";
import { CepStatus, IStock } from "../types/types";
import { GREY_COLOR, formatCep, formatCoupon, formatMoney, getImageUrl } from "../utils/utils";
import useUser from "../storage/useUser";
import useSettings from "../storage/useSettings";
import useCart, { CookieCoupon } from "../storage/useCart";
import { Cookie, Delete as DeleteIcon } from "@mui/icons-material";
import { URL_BACK } from "../components/api";
import DeliveryCard from "../components/DeliveryCard";
import useAddress from "../storage/useAddress";

const debugColors = ['white', 'white', 'white', 'white', 'white', 'white', 'white', 'white']
// const debugColors = ['red', 'green', 'pink', 'blue', 'gray', 'lightBlue', 'orange', 'yellow']

export default function Carrinho() {
    const theme = useTheme();
    const isMediumScreen = useMediaQuery(theme.breakpoints.up('md'));
    const { cacheAddress, searchCepAndStoreLocal } = useAddress();
    const { stocks } = useSettings();
    const { items, cartRes, updateQuantity, removeItemFromCart, updateCartResApi } = useCart();
    const [cep, setCep] = useState<string>(formatCep(cacheAddress?.cep || ""));
    const [cepStatus, setCepStatus] = useState<CepStatus>(CepStatus.incomplete);
    const [coupon, setCoupon] = useState<string>(CookieCoupon.getCoupon());
    const { isLogged } = useUser();

    const handleSearchCep = async () => {
        if (cep.replace(/\D/g, '').length === 8) {
            setCepStatus(CepStatus.loading);
            try {
                const addr = await searchCepAndStoreLocal(cep);
                updateCartResApi(addr, coupon);
                setCepStatus(CepStatus.valid);
            } catch (err) {
                console.log(err);
                setCepStatus(CepStatus.invalid);
            }
        } else {
            setCepStatus(CepStatus.incomplete);
        }
    }

    const handleSearchCoupon = async () => {
        // salva o cupom no cookie
        CookieCoupon.update(coupon);

        // atualiza o carrinho com o novo cupom
        updateCartResApi(cacheAddress, coupon);
    }

    const handleNext = () => {
        if (isLogged()) {
            navigate('/checkout');
        } else {
            navigate('/login?ir=checkout');
        }
    }

    const getStockById = (id: number): IStock | undefined => {
        return stocks.find((s) => s.id === id);
    }

    // Quando entrar na tela, atualiza o cartRes
    useEffect(() => {
        if (items?.length)
            updateCartResApi(cacheAddress, coupon);
    }, []);


    return (
        <Layout hideFooter={true}>
            {(!items || items.length === 0) ?
                <Container
                    sx={{
                        display: 'flex',
                        flexDirection: 'column',
                        alignItems: 'center',
                        justifyContent: 'center',
                        height: '50vh',
                    }}
                >
                    <Typography variant="h5" mb={4}>
                        Seu carrinho está vazio
                    </Typography>
                    <CustomButton title="Ir às compras" onClick={() => navigate('/')} width="50%" />
                </Container>
                :
                <Container>
                    <Typography variant="h4" mt={2}>
                        Carrinho
                    </Typography>
                    <Typography variant="subtitle1" gutterBottom pl={'3px'} pb={2}>
                        <Link href="/">Continuar comprando</Link>
                    </Typography>

                    <Card>
                        <Grid container>
                            <Grid item xs={12} md={8} bgcolor={debugColors[0]}>
                                <CardContent>
                                    {items.map((cartItem) => (
                                        <Box key={`${cartItem.productId}-${cartItem.stockId}`} style={{ display: 'flex' }} height={isMediumScreen ? 120 : 180} mt={4}>
                                            <Box bgcolor={debugColors[1]} width={isMediumScreen ? 100 : 70} >
                                                <img width={isMediumScreen ? 100 : 70} src={getImageUrl(cartItem.picture)} />
                                            </Box>
                                            <Box bgcolor={debugColors[2]} width={668}>
                                                <Typography variant="subtitle2" pl={1}>
                                                    {cartItem.name.length <= 50 ? cartItem.name : cartItem.name.substring(0, 50) + "..."}
                                                </Typography>
                                                <Grid container height={120}>
                                                    <Grid item xs={12} md={6} bgcolor={debugColors[3]}>
                                                        <Box sx={{ display: 'flex', justifyContent: 'space-between' }}>
                                                            <Box ml={1}>
                                                                <Typography variant="body2" color="text.secondary">
                                                                    Cor: {getStockById(cartItem.stockId)?.colorName}
                                                                </Typography>
                                                                <Typography variant="body2" color="text.secondary">
                                                                    Tamanho: {getStockById(cartItem.stockId)?.sizeName}
                                                                </Typography>
                                                            </Box>
                                                        </Box>
                                                    </Grid>
                                                    <Grid item xs={12} md={3} bgcolor={debugColors[4]} pl={1}>
                                                        <QuantityInput
                                                            value={cartItem.quantity}
                                                            onChange={(qtd) => updateQuantity(cartItem.productId, cartItem.stockId, qtd)}
                                                            min={1}
                                                            max={99}
                                                            onMin={() => alert("TODO: Deseja excluir?")}
                                                        />
                                                    </Grid>
                                                    <Grid item xs={9} md={2} bgcolor={debugColors[5]} pl={1} pt="4px">
                                                        <Typography variant="subtitle1" color="text.secondary">
                                                            {formatMoney(cartItem.unitPrice * cartItem.quantity)}
                                                        </Typography>
                                                    </Grid>
                                                    <Grid item xs={1} md={1} bgcolor={debugColors[6]} pl={1}>
                                                        {/* TODO: colocar confirmação para deletar aqui */}
                                                        <IconButton size="small" onClick={() => removeItemFromCart(cartItem.productId, cartItem.stockId)}>
                                                            <DeleteIcon />
                                                        </IconButton>
                                                    </Grid>
                                                </Grid>
                                            </Box>
                                        </Box>
                                    ))}
                                </CardContent>
                            </Grid>

                            <Grid item xs={12} md={4} bgcolor={GREY_COLOR} p={2}>
                                <Box>
                                    <Typography variant="h6">
                                        Entrega
                                    </Typography>
                                    <ButtonInput
                                        value={cep}
                                        onChange={setCep}
                                        onClick={handleSearchCep}
                                        mask={formatCep}
                                        label='INFORME O CEP'
                                        buttonLabel='Calcular'
                                        width='100%'
                                        error={cepStatus === CepStatus.invalid}
                                        helperText={cepStatus === CepStatus.invalid ? 'CEP não encontrado' : ''}
                                    />
                                    {(cepStatus === CepStatus.loading || cepStatus === CepStatus.valid) &&
                                        <Box mt={2}>
                                            <DeliveryCard
                                                isLoadingCep={cepStatus === CepStatus.loading}
                                                deliveryValue={cartRes?.deliveryValue || 0}
                                                deliveryForecast={cartRes?.deliveryForecast || 0}
                                                bgColor={GREY_COLOR}
                                            />
                                        </Box>
                                    }
                                </Box>
                                <Box mt={3} sx={!isMediumScreen ? { pb: 8 } : null}>
                                    <Typography variant="h6">
                                        Cupom
                                    </Typography>
                                    <ButtonInput
                                        value={coupon}
                                        onChange={setCoupon}
                                        mask={formatCoupon}
                                        onClick={handleSearchCoupon}
                                        label='INSIRA O CUPOM'
                                        buttonLabel='APLICAR'
                                        width='100%'
                                    />
                                    {!!(cartRes?.couponValue) &&
                                        <Typography variant="subtitle1" color="text.secondary">
                                            Cupom: {cartRes.couponValue}
                                        </Typography>
                                    }
                                    {!!(cartRes?.deliveryValue) &&
                                        <Typography variant="subtitle1" color="text.secondary">
                                            Frete: {cartRes.deliveryValue}
                                        </Typography>
                                    }
                                    {!!(cartRes?.productsValue) &&
                                        <Typography variant="subtitle1" color="text.secondary">
                                            Subtotal: {cartRes.productsValue}
                                        </Typography>
                                    }

                                    {!!(cartRes?.totalValue) &&
                                        <Typography variant="subtitle1" color="text.secondary">
                                            Total: {cartRes.totalValue}
                                        </Typography>
                                    }
                                </Box>
                                <Box pt={4} sx={!isMediumScreen ? { width: '100%', position: 'fixed', bottom: 0, left: 0 } : null}>
                                    <CustomButton title="Avançar" onClick={handleNext} width="100%" />
                                </Box>
                            </Grid>
                        </Grid>
                    </Card>
                </Container>
            }
        </Layout >
    );
}
