import { Add, Remove } from '@mui/icons-material';
import { IconButton, InputAdornment, TextField } from '@mui/material';
import * as React from 'react';

interface QuantityInputProps {
  value: number;
  onChange: (value: number) => void;
  max?: number;
  min?: number;
  onMin?: () => void
}

export default function QuantityInput({ value, onChange, max, min, onMin }: QuantityInputProps) {
  const handleAdd = () => {
    if(max !== undefined && value < max)
    onChange(value + 1);
  };

  const handleSub = () => {
    if (min !== undefined && value > min)
      onChange(value - 1);
    else if (onMin)
      onMin();
  };

  return (
    <TextField
      hiddenLabel
      size="small"
      sx={{ width: '110px' }}
      value={value}
      InputProps={{
        endAdornment: (
          <InputAdornment position="end">
            <IconButton onClick={handleAdd} edge="end">
              <Add fontSize="small" />
            </IconButton>
          </InputAdornment>
        ),
        startAdornment: (
          <InputAdornment position="start">
            <IconButton onClick={handleSub} edge="start">
              <Remove fontSize="small" />
            </IconButton>
          </InputAdornment>
        ),
      }}
    />
  );
}